import { createContext, useContext, useEffect, useMemo, useState } from 'react';

const AppContext = createContext(null);
const STORAGE_KEY = 'gobus_app_state';

const initialState = {
  user: null,
  token: null,
  selectedTripId: '',
  selectedSeats: [],
  bookingConfirmation: null,
};

export const AppProvider = ({ children }) => {
  const [user, setUser] = useState(initialState.user);
  const [token, setToken] = useState(initialState.token);
  const [selectedTripId, setSelectedTripId] = useState(initialState.selectedTripId);
  const [selectedSeats, setSelectedSeats] = useState(initialState.selectedSeats);
  const [bookingConfirmation, setBookingConfirmation] = useState(initialState.bookingConfirmation);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (!saved) {
      return;
    }

    try {
      const parsed = JSON.parse(saved);
      setUser(parsed.user || null);
      setToken(parsed.token || null);
      setSelectedTripId(parsed.selectedTripId || '');
      setSelectedSeats(parsed.selectedSeats || []);
      setBookingConfirmation(parsed.bookingConfirmation || null);
    } catch {
      localStorage.removeItem(STORAGE_KEY);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(
      STORAGE_KEY,
      JSON.stringify({ user, token, selectedTripId, selectedSeats, bookingConfirmation }),
    );
  }, [user, token, selectedTripId, selectedSeats, bookingConfirmation]);

  const login = (userData, tokenValue) => {
    setUser(userData);
    setToken(tokenValue);
  };

  const logout = () => {
    setUser(null);
    setToken(null);
    setSelectedTripId('');
    setSelectedSeats([]);
    setBookingConfirmation(null);
    localStorage.removeItem(STORAGE_KEY);
  };

  const value = useMemo(
    () => ({
      user,
      token,
      selectedTripId,
      selectedSeats,
      bookingConfirmation,
      login,
      logout,
      setSelectedTripId,
      setSelectedSeats,
      setBookingConfirmation,
    }),
    [user, token, selectedTripId, selectedSeats, bookingConfirmation],
  );

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useAppContext must be used within AppProvider');
  }
  return context;
};

import { useState, useEffect } from 'react';
import { Activity, UserCheck, Trash2, Edit, PlusCircle } from 'lucide-react';
import api from '../services/api';
import './AdminActivityLogs.css';

export default function AdminActivityLogs() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [actionFilter, setActionFilter] = useState('');
  const [pagination, setPagination] = useState({});

  useEffect(() => {
    fetchLogs();
  }, [page, actionFilter]);

  const fetchLogs = async () => {
    try {
      setLoading(true);
      const query = new URLSearchParams({
        page,
        ...(actionFilter && { action: actionFilter })
      });
      const data = await api.getAdminActivityLogs(query.toString());
      setLogs(data.logs);
      setPagination(data.pagination);
    } catch (err) {
      alert('Failed to fetch activity logs: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const getActionIcon = (action) => {
    switch (action) {
      case 'CREATE_TRIP':
      case 'CREATE_ANNOUNCEMENT':
        return <PlusCircle size={18} className="action-icon create" />;
      case 'UPDATE_TRIP':
      case 'UPDATE_REFUND_STATUS':
      case 'UPDATE_BOOKING_STATUS':
        return <Edit size={18} className="action-icon update" />;
      case 'DELETE_TRIP':
      case 'DELETE_BOOKING':
      case 'DELETE_ANNOUNCEMENT':
        return <Trash2 size={18} className="action-icon delete" />;
      case 'LOGIN':
        return <UserCheck size={18} className="action-icon login" />;
      default:
        return <Activity size={18} className="action-icon" />;
    }
  };

  const getActionColor = (action) => {
    if (action.startsWith('CREATE')) return '#26de81';
    if (action.startsWith('UPDATE')) return '#4facfe';
    if (action.startsWith('DELETE')) return '#ff6b6b';
    return '#667eea';
  };

  const uniqueActions = [...new Set(logs.map(log => log.action))];

  if (loading && logs.length === 0) {
    return <div className="logs-loading">Loading activity logs...</div>;
  }

  return (
    <div className="logs-container">
      <div className="logs-header">
        <h2>Admin Activity Log</h2>
        <p>Track all administrative operations</p>
      </div>

      <div className="logs-filter">
        <select
          value={actionFilter}
          onChange={(e) => {
            setActionFilter(e.target.value);
            setPage(1);
          }}
          className="action-select"
        >
          <option value="">All Actions</option>
          {uniqueActions.map(action => (
            <option key={action} value={action}>{action}</option>
          ))}
        </select>
      </div>

      <div className="logs-list">
        {logs.length === 0 ? (
          <div className="no-logs">No activity logs found</div>
        ) : (
          logs.map((log) => (
            <div key={log._id} className="log-item">
              <div className="log-icon" style={{ color: getActionColor(log.action) }}>
                {getActionIcon(log.action)}
              </div>

              <div className="log-details">
                <div className="log-header">
                  <h4 className="log-action">{log.action}</h4>
                  <span className="log-time">
                    {new Date(log.createdAt).toLocaleString()}
                  </span>
                </div>

                <p className="log-admin">
                  <strong>Admin:</strong> {log.adminEmail}
                </p>

                {log.description && (
                  <p className="log-description">{log.description}</p>
                )}

                <div className="log-meta">
                  {log.resourceType && (
                    <span className="meta-item">
                      <strong>Resource:</strong> {log.resourceType}
                    </span>
                  )}
                  {log.changes && Object.keys(log.changes).length > 0 && (
                    <span className="meta-item">
                      <strong>Changes:</strong> {Object.keys(log.changes).join(', ')}
                    </span>
                  )}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Pagination */}
      {pagination.pages > 1 && (
        <div className="pagination">
          <button
            onClick={() => setPage(Math.max(1, page - 1))}
            disabled={page === 1}
            className="btn-pagination"
          >
            Previous
          </button>
          <span className="page-info">
            Page {pagination.currentPage} of {pagination.pages}
          </span>
          <button
            onClick={() => setPage(Math.min(pagination.pages, page + 1))}
            disabled={page === pagination.pages}
            className="btn-pagination"
          >
            Next
          </button>
        </div>
      )}

      {/* Stats */}
      <div className="logs-stats">
        <div className="stat-card">
          <span className="stat-label">Total Logs</span>
          <span className="stat-value">{pagination.total}</span>
        </div>
        <div className="stat-card create">
          <span className="stat-label">Create Operations</span>
          <span className="stat-value">
            {logs.filter(l => l.action.startsWith('CREATE')).length}
          </span>
        </div>
        <div className="stat-card update">
          <span className="stat-label">Update Operations</span>
          <span className="stat-value">
            {logs.filter(l => l.action.startsWith('UPDATE')).length}
          </span>
        </div>
        <div className="stat-card delete">
          <span className="stat-label">Delete Operations</span>
          <span className="stat-value">
            {logs.filter(l => l.action.startsWith('DELETE')).length}
          </span>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { BarChart, Bar, LineChart, Line, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { DollarSign, TrendingUp, AlertCircle, MapPin } from 'lucide-react';
import api from '../services/api';
import './AdminAnalytics.css';

export default function AdminAnalytics() {
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    fetchAnalytics();
  }, []);

  const fetchAnalytics = async () => {
    try {
      setLoading(true);
      const query = new URLSearchParams();
      if (startDate) query.append('startDate', startDate);
      if (endDate) query.append('endDate', endDate);
      const data = await api.getAdminAnalytics(query.toString());
      setAnalytics(data);
    } catch (err) {
      alert('Failed to fetch analytics: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleFilter = () => {
    fetchAnalytics();
  };

  const COLORS = ['#667eea', '#764ba2', '#f093fb', '#4facfe', '#00f2fe'];

  if (loading) return <div className="analytics-loading">Loading analytics...</div>;
  if (!analytics) return <div className="analytics-loading">No data available</div>;

  return (
    <div className="analytics-container">
      <div className="analytics-header">
        <h2>Advanced Analytics</h2>
        <div className="filter-section">
          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
            placeholder="Start Date"
          />
          <input
            type="date"
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
            placeholder="End Date"
          />
          <button onClick={handleFilter} className="btn-filter">
            <TrendingUp size={18} /> Filter
          </button>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpi-cards">
        <div className="kpi-card">
          <div className="kpi-icon" style={{ color: '#667eea' }}>
            <DollarSign />
          </div>
          <div className="kpi-content">
            <h3>Total Bookings</h3>
            <p className="kpi-value">{analytics.totalBookings}</p>
          </div>
        </div>
        <div className="kpi-card">
          <div className="kpi-icon" style={{ color: '#4facfe' }}>
            <AlertCircle />
          </div>
          <div className="kpi-content">
            <h3>Cancellation Rate</h3>
            <p className="kpi-value">{analytics.cancellationRate}%</p>
            <p className="kpi-subtext">({analytics.cancelledBookings} cancelled)</p>
          </div>
        </div>
        <div className="kpi-card">
          <div className="kpi-icon" style={{ color: '#f093fb' }}>
            <MapPin />
          </div>
          <div className="kpi-content">
            <h3>Top Routes</h3>
            <p className="kpi-value">{analytics.topRoutes.length}</p>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="charts-grid">
        {/* Booking Trends */}
        {analytics.bookingTrends && analytics.bookingTrends.length > 0 && (
          <div className="chart-box">
            <h3>Booking Trends (Last 30 Days)</h3>
            <ResponsiveContainer width="100%" height={300}>
              <LineChart data={analytics.bookingTrends}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="_id" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Line
                  type="monotone"
                  dataKey="count"
                  stroke="#667eea"
                  name="Bookings"
                />
                <Line
                  type="monotone"
                  dataKey="revenue"
                  stroke="#764ba2"
                  name="Revenue (₹)"
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* Revenue by Route */}
        {analytics.revenueByRoute && analytics.revenueByRoute.length > 0 && (
          <div className="chart-box">
            <h3>Top 10 Routes by Revenue</h3>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={analytics.revenueByRoute}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="_id" angle={-45} textAnchor="end" height={100} />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="totalRevenue" fill="#667eea" name="Revenue (₹)" />
                <Bar dataKey="bookingCount" fill="#4facfe" name="Bookings" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* Status Breakdown */}
        {analytics.statusBreakdown && analytics.statusBreakdown.length > 0 && (
          <div className="chart-box">
            <h3>Booking Status Breakdown</h3>
            <ResponsiveContainer width="100%" height={300}>
              <PieChart>
                <Pie
                  data={analytics.statusBreakdown}
                  dataKey="count"
                  nameKey="_id"
                  cx="50%"
                  cy="50%"
                  outerRadius={80}
                  label
                >
                  {analytics.statusBreakdown.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* Top Routes */}
        {analytics.topRoutes && analytics.topRoutes.length > 0 && (
          <div className="chart-box">
            <h3>Top 5 Most Booked Routes</h3>
            <div className="routes-list">
              {analytics.topRoutes.map((route, idx) => (
                <div key={idx} className="route-item">
                  <span className="route-rank">#{idx + 1}</span>
                  <span className="route-name">{route._id}</span>
                  <span className="route-bookings">{route.bookings} bookings</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { AlertCircle, MessageCircle, Plus, Trash2, Info } from 'lucide-react';
import api from '../services/api';
import './AdminAnnouncements.css';

export default function AdminAnnouncements() {
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [pagination, setPagination] = useState({});
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    message: '',
    type: 'info',
    expiresAt: ''
  });

  useEffect(() => {
    fetchAnnouncements();
  }, [page]);

  const fetchAnnouncements = async () => {
    try {
      setLoading(true);
      const data = await api.getAdminAnnouncements(`page=${page}`);
      setAnnouncements(data.announcements);
      setPagination(data.pagination);
    } catch (err) {
      alert('Failed to fetch announcements: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.title || !formData.message) {
      alert('Title and message are required');
      return;
    }

    try {
      await api.createAdminAnnouncement(formData);
      alert('Announcement created successfully!');
      setFormData({ title: '', message: '', type: 'info', expiresAt: '' });
      setShowForm(false);
      fetchAnnouncements();
    } catch (err) {
      alert('Failed to create announcement: ' + err.message);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this announcement?')) return;

    try {
      await api.deleteAdminAnnouncement(id);
      alert('Announcement deleted successfully!');
      fetchAnnouncements();
    } catch (err) {
      alert('Failed to delete announcement: ' + err.message);
    }
  };

  const getTypeIcon = (type) => {
    switch (type) {
      case 'warning':
        return <AlertCircle size={20} />;
      case 'success':
        return <MessageCircle size={20} />;
      default:
        return <Info size={20} />;
    }
  };

  const getTypeColor = (type) => {
    switch (type) {
      case 'warning':
        return '#ff9f43';
      case 'success':
        return '#26de81';
      default:
        return '#4facfe';
    }
  };

  if (loading && announcements.length === 0) {
    return <div className="announcements-loading">Loading announcements...</div>;
  }

  return (
    <div className="announcements-container">
      <div className="announcements-header">
        <div>
          <h2>Announcements</h2>
          <p>Post announcements visible to all users</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="btn-create"
        >
          <Plus size={20} />
          {showForm ? 'Cancel' : 'New Announcement'}
        </button>
      </div>

      {/* Form */}
      {showForm && (
        <div className="form-section">
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Title *</label>
              <input
                type="text"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                placeholder="e.g., Server Maintenance"
              />
            </div>

            <div className="form-group">
              <label>Message *</label>
              <textarea
                value={formData.message}
                onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                placeholder="Enter announcement message..."
                rows={5}
              />
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Type</label>
                <select
                  value={formData.type}
                  onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                >
                  <option value="info">Info</option>
                  <option value="warning">Warning</option>
                  <option value="success">Success</option>
                </select>
              </div>

              <div className="form-group">
                <label>Expires At (Optional)</label>
                <input
                  type="datetime-local"
                  value={formData.expiresAt}
                  onChange={(e) => setFormData({ ...formData, expiresAt: e.target.value })}
                />
              </div>
            </div>

            <button type="submit" className="btn-submit">
              Create Announcement
            </button>
          </form>
        </div>
      )}

      {/* Announcements List */}
      <div className="announcements-list">
        {announcements.length === 0 ? (
          <div className="no-announcements">
            <MessageCircle size={40} />
            <p>No announcements yet. Create one to get started!</p>
          </div>
        ) : (
          announcements.map((announcement) => (
            <div
              key={announcement._id}
              className="announcement-card"
              style={{ '--type-color': getTypeColor(announcement.type) }}
            >
              <div className="announcement-icon" style={{ color: getTypeColor(announcement.type) }}>
                {getTypeIcon(announcement.type)}
              </div>

              <div className="announcement-content">
                <div className="announcement-header">
                  <h3>{announcement.title}</h3>
                  <span className="announcement-type">{announcement.type}</span>
                </div>

                <p className="announcement-message">{announcement.message}</p>

                <div className="announcement-meta">
                  <span className="meta-item">
                    By: {announcement.createdBy?.email}
                  </span>
                  <span className="meta-item">
                    {new Date(announcement.createdAt).toLocaleDateString()}
                  </span>
                  {announcement.expiresAt && (
                    <span className="meta-item">
                      Expires: {new Date(announcement.expiresAt).toLocaleDateString()}
                    </span>
                  )}
                </div>
              </div>

              <button
                onClick={() => handleDelete(announcement._id)}
                className="btn-delete"
              >
                <Trash2 size={18} />
              </button>
            </div>
          ))
        )}
      </div>

      {/* Pagination */}
      {pagination.pages > 1 && (
        <div className="pagination">
          <button
            onClick={() => setPage(Math.max(1, page - 1))}
            disabled={page === 1}
            className="btn-pagination"
          >
            Previous
          </button>
          <span className="page-info">
            Page {pagination.currentPage} of {pagination.pages}
          </span>
          <button
            onClick={() => setPage(Math.min(pagination.pages, page + 1))}
            disabled={page === pagination.pages}
            className="btn-pagination"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { api } from '../services/api';
import { ArrowLeft, Search, Trash2 } from 'lucide-react';
import './AdminBookings.css';

const AdminBookings = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [pagination, setPagination] = useState({});
  const [currentPage, setCurrentPage] = useState(1);
  const navigate = useNavigate();
  const adminToken = localStorage.getItem('admin_token');

  useEffect(() => {
    if (!adminToken) {
      navigate('/admin/login');
      return;
    }
    fetchBookings();
  }, [adminToken, currentPage, search, statusFilter, navigate]);

  const fetchBookings = async () => {
    try {
      setLoading(true);
      const data = await api.getAdminBookings({ page: currentPage, search, status: statusFilter });
      setBookings(data.bookings);
      setPagination(data.pagination);
    } catch (err) {
      setError('Failed to load bookings');
      console.error('Bookings fetch error:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusChange = async (bookingId, newStatus) => {
    try {
      await api.updateAdminBookingStatus(bookingId, { status: newStatus });
      fetchBookings();
    } catch (err) {
      setError('Failed to update booking status');
    }
  };

  const handleDelete = async (bookingId) => {
    if (!window.confirm('Delete this booking?')) return;
    try {
      await api.deleteAdminBooking(bookingId);
      fetchBookings();
    } catch (err) {
      setError('Failed to delete booking');
    }
  };

  if (loading && bookings.length === 0) {
    return (
      <div className="admin-bookings">
        <div className="loading">Loading bookings...</div>
      </div>
    );
  }

  return (
    <div className="admin-bookings">
      <div className="page-header">
        <Link to="/admin/dashboard" className="back-link">
          <ArrowLeft size={20} /> Back
        </Link>
        <h1>Booking Management</h1>
      </div>

      <div className="filter-section">
        <div className="search-section">
          <Search size={20} />
          <input
            type="text"
            placeholder="Search by email or name..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value);
              setCurrentPage(1);
            }}
            className="search-input"
          />
        </div>

        <select
          value={statusFilter}
          onChange={(e) => {
            setStatusFilter(e.target.value);
            setCurrentPage(1);
          }}
          className="status-filter"
        >
          <option value="">All Status</option>
          <option value="confirmed">Confirmed</option>
          <option value="pending">Pending</option>
          <option value="cancelled">Cancelled</option>
        </select>
      </div>

      {error && <div className="error">{error}</div>}

      <div className="bookings-table-container">
        {bookings.length > 0 ? (
          <table className="bookings-table">
            <thead>
              <tr>
