import { useState, useEffect } from 'react';
import { Check, X, Clock, DollarSign } from 'lucide-react';
import api from '../services/api';
import './AdminRefunds.css';

export default function AdminRefunds() {
  const [refunds, setRefunds] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [statusFilter, setStatusFilter] = useState('');
  const [pagination, setPagination] = useState({});
  const [selectedRefund, setSelectedRefund] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [refundStatus, setRefundStatus] = useState('');
  const [notes, setNotes] = useState('');

  useEffect(() => {
    fetchRefunds();
  }, [page, statusFilter]);

  const fetchRefunds = async () => {
    try {
      setLoading(true);
      const query = new URLSearchParams({
        page,
        ...(statusFilter && { status: statusFilter })
      });
      const data = await api.getAdminRefunds(query.toString());
      setRefunds(data.refunds);
      setPagination(data.pagination);
    } catch (err) {
      alert('Failed to fetch refunds: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const openModal = (refund) => {
    setSelectedRefund(refund);
    setRefundStatus(refund.status);
    setNotes(refund.notes || '');
    setShowModal(true);
  };

  const handleUpdateStatus = async () => {
    if (!refundStatus) {
      alert('Please select a status');
      return;
    }
    try {
      await api.updateAdminRefundStatus(selectedRefund._id, refundStatus, notes);
      alert('Refund status updated successfully');
      setShowModal(false);
      fetchRefunds();
    } catch (err) {
      alert('Failed to update refund: ' + err.message);
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'approved':
        return <Check size={18} className="status-icon approved" />;
      case 'rejected':
        return <X size={18} className="status-icon rejected" />;
      case 'completed':
        return <DollarSign size={18} className="status-icon completed" />;
      default:
        return <Clock size={18} className="status-icon pending" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'approved':
        return '#4facfe';
      case 'rejected':
        return '#ff6b6b';
      case 'completed':
        return '#26de81';
      default:
        return '#ffa502';
    }
  };

  if (loading && refunds.length === 0) {
    return <div className="refunds-loading">Loading refunds...</div>;
  }

  return (
    <div className="refunds-container">
      <div className="refunds-header">
        <h2>Refund Management</h2>
        <div className="filter-controls">
          <select
            value={statusFilter}
            onChange={(e) => {
              setStatusFilter(e.target.value);
              setPage(1);
            }}
            className="status-filter"
          >
            <option value="">All Status</option>
            <option value="pending">Pending</option>
            <option value="approved">Approved</option>
            <option value="rejected">Rejected</option>
            <option value="completed">Completed</option>
          </select>
        </div>
      </div>

      <div className="refunds-table-wrapper">
        <table className="refunds-table">
          <thead>
            <tr>
              <th>Booking ID</th>
              <th>Passenger</th>
              <th>Trip</th>
              <th>Refund Amount</th>
              <th>Status</th>
              <th>Reason</th>
              <th>Date</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {refunds.map((refund) => (
              <tr key={refund._id}>
                <td className="booking-id">{refund.bookingId?._id?.toString().slice(-8) || 'N/A'}</td>
                <td>
                  <div className="passenger-info">
                    <p className="name">{refund.userId?.name || 'Unknown'}</p>
                    <p className="email">{refund.userId?.email || 'N/A'}</p>
                  </div>
                </td>
                <td className="trip-info">
                  {refund.tripId?.busNumber || 'N/A'}
                  <br />
                  <small>{refund.tripId?.from || ''} → {refund.tripId?.to || ''}</small>
                </td>
                <td className="amount">₹{refund.refundAmount?.toFixed(2) || '0.00'}</td>
                <td className="status-cell">
                  <div className="status-badge" style={{ borderColor: getStatusColor(refund.status) }}>
                    {getStatusIcon(refund.status)}
                    <span>{refund.status}</span>
                  </div>
                </td>
                <td className="reason">{refund.reason || 'N/A'}</td>
                <td className="date">{new Date(refund.createdAt).toLocaleDateString()}</td>
                <td className="action">
                  <button
                    onClick={() => openModal(refund)}
                    className="btn-update"
                    disabled={refund.status === 'completed'}
                  >
                    Update
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {refunds.length === 0 && (
          <div className="no-data">No refunds found</div>
        )}
      </div>

      {/* Pagination */}
      <div className="pagination">
        <button
          onClick={() => setPage(Math.max(1, page - 1))}
          disabled={page === 1}
          className="btn-pagination"
        >
          Previous
        </button>
        <span className="page-info">
          Page {pagination.currentPage} of {pagination.pages}
        </span>
        <button
          onClick={() => setPage(Math.min(pagination.pages, page + 1))}
          disabled={page === pagination.pages}
          className="btn-pagination"
        >
          Next
        </button>
      </div>

      {/* Update Modal */}
      {showModal && selectedRefund && (
        <div className="modal-overlay">
          <div className="modal-content">
            <h3>Update Refund Status</h3>
            <div className="modal-body">
              <p>
                <strong>Passenger:</strong> {selectedRefund.userId?.name}
              </p>
              <p>
                <strong>Amount:</strong> ₹{selectedRefund.refundAmount?.toFixed(2)}
              </p>
              <p>
                <strong>Reason:</strong> {selectedRefund.reason}
              </p>

              <div className="form-group">
                <label>Status</label>
                <select
                  value={refundStatus}
                  onChange={(e) => setRefundStatus(e.target.value)}
                >
                  <option value="pending">Pending</option>
                  <option value="approved">Approved</option>
                  <option value="rejected">Rejected</option>
                  <option value="completed">Completed</option>
                </select>
              </div>

              <div className="form-group">
                <label>Notes</label>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Add processing notes..."
                  rows={4}
                />
              </div>
            </div>

            <div className="modal-footer">
              <button
                onClick={() => setShowModal(false)}
                className="btn-cancel"
              >
                Cancel
              </button>
              <button
                onClick={handleUpdateStatus}
                className="btn-submit"
              >
                Update Status
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Download, FileText, Calendar } from 'lucide-react';
import api from '../services/api';
import './AdminReports.css';

export default function AdminReports() {
  const [loading, setLoading] = useState(false);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [bookingStatus, setBookingStatus] = useState('');

  const handleExportBookings = async () => {
    if (startDate && endDate && new Date(startDate) > new Date(endDate)) {
      alert('Start date must be before end date');
      return;
    }

    try {
      setLoading(true);
      const query = new URLSearchParams();
      if (startDate) query.append('startDate', startDate);
      if (endDate) query.append('endDate', endDate);
      if (bookingStatus) query.append('status', bookingStatus);

      const response = await fetch(
        `/api/admin/reports/bookings?${query.toString()}`,
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem('admin_token')}`
          }
        }
      );

      if (!response.ok) throw new Error('Export failed');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'bookings-report.csv';
      a.click();
      window.URL.revokeObjectURL(url);
      alert('Bookings exported successfully!');
    } catch (err) {
      alert('Failed to export bookings: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleExportTrips = async () => {
    try {
      setLoading(true);
      const response = await fetch('/api/admin/reports/trips', {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('admin_token')}`
        }
      });

      if (!response.ok) throw new Error('Export failed');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'trips-report.csv';
      a.click();
      window.URL.revokeObjectURL(url);
      alert('Trips exported successfully!');
    } catch (err) {
      alert('Failed to export trips: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="reports-container">
      <div className="reports-header">
        <h2>Reports & Export</h2>
        <p>Generate and download reports in CSV format</p>
      </div>

      <div className="reports-grid">
        {/* Bookings Report */}
        <div className="report-card">
          <div className="report-icon">
            <FileText size={40} />
          </div>
          <h3>Bookings Report</h3>
          <p className="report-desc">Export all bookings with filters</p>

          <div className="filter-form">
            <div className="form-group">
              <label>From Date</label>
              <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
            </div>

            <div className="form-group">
              <label>To Date</label>
              <input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>

            <div className="form-group">
              <label>Status</label>
              <select
                value={bookingStatus}
                onChange={(e) => setBookingStatus(e.target.value)}
              >
                <option value="">All Status</option>
                <option value="pending">Pending</option>
                <option value="confirmed">Confirmed</option>
                <option value="cancelled">Cancelled</option>
              </select>
            </div>

            <button
              onClick={handleExportBookings}
              disabled={loading}
              className="btn-export"
            >
              <Download size={18} />
              {loading ? 'Exporting...' : 'Export Bookings'}
            </button>
          </div>
        </div>

        {/* Trips Report */}
        <div className="report-card">
          <div className="report-icon" style={{ color: '#4facfe' }}>
            <FileText size={40} />
          </div>
          <h3>Trips Report</h3>
          <p className="report-desc">Export all active trips</p>

          <div className="filter-form">
            <p className="info-text">
              This report includes all trips with current availability and pricing information.
            </p>

            <button
              onClick={handleExportTrips}
              disabled={loading}
              className="btn-export"
            >
              <Download size={18} />
              {loading ? 'Exporting...' : 'Export Trips'}
            </button>
          </div>
        </div>
      </div>

      {/* Report Information */}
      <div className="report-info">
        <h3>Report Details</h3>
        <div className="info-grid">
          <div className="info-item">
            <h4>Bookings Report Contains</h4>
            <ul>
              <li>Booking ID</li>
              <li>Passenger Name & Email</li>
              <li>Bus Number & Route</li>
              <li>Booking Amount</li>
              <li>Status</li>
              <li>Date</li>
            </ul>
          </div>
          <div className="info-item">
            <h4>Trips Report Contains</h4>
            <ul>
              <li>Bus Number</li>
              <li>Route (From → To)</li>
              <li>Departure & Arrival Time</li>
              <li>Price & Total Seats</li>
              <li>Available Seats</li>
              <li>Operator</li>
            </ul>
          </div>
        </div>
      </div>

      <div className="tips-section">
        <h3>📋 Tips for Reports</h3>
        <ul>
          <li>Reports are generated in CSV format for easy analysis in Excel/Google Sheets</li>
          <li>Date filters apply only to Bookings Report</li>
          <li>Use status filter to focus on specific booking types</li>
          <li>All reports include timestamp of generation</li>
          <li>No sensitive data like passwords is included</li>
        </ul>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { api } from '../services/api';
import { ArrowLeft, Search, Plus, Trash2 } from 'lucide-react';
import './AdminTrips.css';

const AdminTrips = () => {
  const [trips, setTrips] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [pagination, setPagination] = useState({});
  const [currentPage, setCurrentPage] = useState(1);
  const [showAddModal, setShowAddModal] = useState(false);
  const navigate = useNavigate();
  const adminToken = localStorage.getItem('admin_token');

  useEffect(() => {
    if (!adminToken) {
      navigate('/admin/login');
      return;
    }
    fetchTrips();
  }, [adminToken, currentPage, search, navigate]);

  const fetchTrips = async () => {
    try {
      setLoading(true);
      const data = await api.getAdminTrips({ page: currentPage, search });
      setTrips(data.trips);
      setPagination(data.pagination);
    } catch (err) {
      setError('Failed to load trips');
      console.error('Trips fetch error:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (tripId) => {
    if (!window.confirm('Delete this trip?')) return;
    try {
      await api.deleteAdminTrip(tripId);
      fetchTrips();
    } catch (err) {
      setError('Failed to delete trip');
    }
  };

  if (loading && trips.length === 0) {
    return (
      <div className="admin-trips">
        <div className="loading">Loading trips...</div>
      </div>
    );
  }

  return (
    <div className="admin-trips">
      <div className="page-header">
        <Link to="/admin/dashboard" className="back-link">
          <ArrowLeft size={20} /> Back
        </Link>
        <div className="header-title">
          <h1>Trip Management</h1>
          <button className="add-btn" onClick={() => setShowAddModal(true)}>
            <Plus size={20} /> Add Trip
          </button>
        </div>
      </div>

      <div className="search-section">
        <Search size={20} />
        <input
          type="text"
          placeholder="Search by route or bus number..."
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setCurrentPage(1);
          }}
          className="search-input"
        />
      </div>

      {error && <div className="error">{error}</div>}

      <div className="trips-table-container">
        {trips.length > 0 ? (
          <table className="trips-table">
            <thead>
              <tr>
                <th>Bus Number</th>
                <th>Route</th>
                <th>Departure</th>
                <th>Price</th>
                <th>Seats</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {trips.map((trip) => (
                <tr key={trip._id}>
                  <td className="bus-number">{trip.busNumber}</td>
                  <td>{trip.from} → {trip.to}</td>
                  <td>{trip.departure}</td>
                  <td>₹{trip.price}</td>
                  <td>{trip.availableSeats}/{trip.seats}</td>
                  <td>
                    <button
                      className="delete-btn"
                      onClick={() => handleDelete(trip._id)}
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <div className="no-data">No trips found</div>
        )}
      </div>

      {pagination.pages > 1 && (
        <div className="pagination">
          <button
            onClick={() => setCurrentPage(currentPage - 1)}
            disabled={currentPage === 1}
          >
            Previous
          </button>
          {Array.from({ length: pagination.pages }, (_, i) => i + 1).map((page) => (
            <button
              key={page}
              onClick={() => setCurrentPage(page)}
              className={page === currentPage ? 'active' : ''}
            >
              {page}
            </button>
          ))}
          <button
            onClick={() => setCurrentPage(currentPage + 1)}
            disabled={currentPage === pagination.pages}
          >
            Next
          </button>
        </div>
      )}

      {showAddModal && (
        <AddTripModal
          onClose={() => setShowAddModal(false)}
          onSuccess={() => {
            setShowAddModal(false);
            fetchTrips();
          }}
        />
      )}
    </div>
  );
};

