import { Clock, Star, Filter, ChevronRight } from 'lucide-react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { useEffect, useState } from 'react';
import { searchTrips } from '../services/api.js';
import { useAppContext } from '../context/AppContext.jsx';
import './SearchResults.css';

const SearchResults = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { setSelectedTripId } = useAppContext();
  const [buses, setBuses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const from = searchParams.get('from') || 'Mumbai';
  const to = searchParams.get('to') || 'Pune';
  const date = searchParams.get('date') || 'Today';

  useEffect(() => {
    let active = true;
    setLoading(true);
    setError('');

    searchTrips({ from, to })
      .then((payload) => {
        if (!active) return;
        setBuses(payload.results);
      })
      .catch((err) => {
        if (!active) return;
        setError(err.message);
      })
      .finally(() => {
        if (!active) return;
        setLoading(false);
      });

    return () => {
      active = false;
    };
  }, [from, to]);

  return (
    <div className="search-results-page animate-fade-in">
      <div className="search-summary glass-panel">
        <div className="container summary-container">
          <div className="route-details">
            <h2>{from} <ChevronRight size={20} className="text-secondary" /> {to}</h2>
            <p className="text-muted"><Clock size={14} /> {date} • {loading ? 'Loading...' : `${buses.length} Buses Found`}</p>
          </div>
          <Link to="/" className="btn btn-outline"><Filter size={18} /> Modify Search</Link>
        </div>
      </div>

      <div className="container results-layout">
        <div className="filters-sidebar">
          <h3>Filters</h3>

          <div className="filter-group">
            <h4 className="filter-title">Bus Type</h4>
            <label className="checkbox-label"><input type="checkbox" /> AC</label>
            <label className="checkbox-label"><input type="checkbox" /> Non-AC</label>
            <label className="checkbox-label"><input type="checkbox" /> Sleeper</label>
            <label className="checkbox-label"><input type="checkbox" /> Seater</label>
          </div>

          <div className="filter-group">
            <h4 className="filter-title">Departure Time</h4>
            <label className="checkbox-label"><input type="checkbox" /> Before 6 AM</label>
            <label className="checkbox-label"><input type="checkbox" /> 6 AM to 12 PM</label>
            <label className="checkbox-label"><input type="checkbox" /> 12 PM to 6 PM</label>
            <label className="checkbox-label"><input type="checkbox" /> After 6 PM</label>
          </div>
        </div>

        <div className="bus-list">
          {loading && <p className="loader-text">Loading available routes...</p>}
          {error && <p className="error-text">{error}</p>}
          {!loading && !error && buses.length === 0 && (
            <p className="empty-state">No buses found for the selected route. Try another search.</p>
          )}

          {buses.map((bus) => (
            <div
              key={bus.id}
              className="bus-card"
              onClick={() => {
                setSelectedTripId(bus.id);
                navigate(`/trip/${bus.id}`);
              }}
              style={{ cursor: 'pointer' }}
            >
              <div className="bus-card-header">
                <div>
                  <h3 className="operator-name">{bus.operator}</h3>
                  <p className="bus-type">{bus.type}</p>
                </div>
                <div className="bus-rating">
                  <Star size={14} className="star-icon" /> {bus.rating}
                </div>
              </div>

              <div className="bus-timing-row">
                <div className="time-block">
                  <span className="time">{bus.departure}</span>
                  <span className="location">{from}</span>
                </div>
                <div className="duration-block">
                  <span className="duration-line"></span>
                  <span className="duration-text">{bus.duration}</span>
                  <span className="duration-line"></span>
                </div>
                <div className="time-block right-align">
                  <span className="time">{bus.arrival}</span>
                  <span className="location">{to}</span>
                </div>
              </div>

              <div className="bus-card-footer">
                <div className="price-info">
                  <span className="price">{bus.price}</span>
                  <span className="seats-left">{bus.seatsLeft} Seats left</span>
                </div>
                <Link
                  to={`/seats?tripId=${bus.id}`}
                  className="btn btn-primary select-seat-btn"
                  onClick={(e) => {
                    e.stopPropagation();
                    setSelectedTripId(bus.id);
                  }}
                >
                  Select Seats
                </Link>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};
export default SearchResults;

import { useEffect, useState } from 'react';
import { Armchair, ChevronRight } from 'lucide-react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { getSeats } from '../services/api.js';
import { useAppContext } from '../context/AppContext.jsx';
import './SeatSelection.css';

const SeatSelection = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { selectedTripId, selectedSeats, setSelectedSeats, setSelectedTripId } = useAppContext();
  const [trip, setTrip] = useState(null);
  const [seatMap, setSeatMap] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const tripId = searchParams.get('tripId') || selectedTripId;

  useEffect(() => {
    if (!tripId) {
      navigate('/search');
      return;
    }

    setSelectedTripId(tripId);
    if (tripId !== selectedTripId) {
      setSelectedSeats([]);
    }

    let active = true;
    setLoading(true);
    setError('');

    getSeats(tripId)
      .then((payload) => {
        if (!active) return;
        setTrip(payload);
        setSeatMap(payload.seatMap || []);
      })
      .catch((err) => {
        if (!active) return;
        setError(err.message);
      })
      .finally(() => {
        if (!active) return;
        setLoading(false);
      });

    return () => {
      active = false;
    };
  }, [tripId, selectedTripId, navigate, setSelectedSeats, setSelectedTripId]);

  const toggleSeat = (seatId) => {
    if (selectedSeats.includes(seatId)) {
      setSelectedSeats(selectedSeats.filter((id) => id !== seatId));
      return;
    }

    if (selectedSeats.length >= 6) {
      alert('You can select up to 6 seats max.');
      return;
    }

    setSelectedSeats([...selectedSeats, seatId]);
  };

  const getSeatStatus = (seatId) => {
    if (selectedSeats.includes(seatId)) return 'selected';
    const seat = seatMap.find((item) => item.id === seatId);
    if (seat?.status === 'booked') return 'booked';
    return 'available';
  };

  const renderSeat = (seatId) => {
    const status = getSeatStatus(seatId);
    return (
      <div
        key={seatId}
        className={`seat ${status}`}
        onClick={() => status !== 'booked' && toggleSeat(seatId)}
      >
        <Armchair size={24} />
        <span className="seat-label">{seatId}</span>
      </div>
    );
  };

  const calculateTotal = () => (selectedSeats.length * (trip?.price || 0));

  if (loading) {
    return (
      <div className="seat-selection-page animate-fade-in">
        <div className="container selection-layout">
          <p>Loading seats...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="seat-selection-page animate-fade-in">
        <div className="container selection-layout">
          <p className="error-text">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="seat-selection-page animate-fade-in">
      <div className="container selection-layout">
        <div className="bus-layout-card">
          <h2 className="layout-title">Select Your Seats</h2>

          <div className="seat-legend">
            <div className="legend-item"><div className="color-box available"></div> Available</div>
            <div className="legend-item"><div className="color-box selected"></div> Selected</div>
            <div className="legend-item"><div className="color-box booked"></div> Booked</div>
          </div>

          <div className="bus-chassis">
            <div className="steering-wheel">Driver</div>
            <div className="seats-grid">
              {Array.from({ length: 10 }).map((_, rowIndex) => {
                const rowNum = rowIndex + 1;
                return (
                  <div key={rowNum} className="seat-row">
                    <div className="seat-pair">
                      {renderSeat(`${rowNum}A`)}
                      {renderSeat(`${rowNum}B`)}
                    </div>
                    <div className="aisle"></div>
                    <div className="seat-pair">
                      {renderSeat(`${rowNum}C`)}
                      {renderSeat(`${rowNum}D`)}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        <div className="selection-summary-card">
          <div className="trip-recap">
            <h3>{trip?.operator}</h3>
            <p className="text-muted">{trip?.route} • {trip?.departure}</p>
          </div>

          <div className="summary-details">
            <div className="summary-row">
              <span className="text-muted">Seat No.</span>
              <span className="font-semibold">{selectedSeats.length > 0 ? selectedSeats.join(', ') : 'None selected'}</span>
            </div>
            <div className="summary-row">
              <span className="text-muted">Per Seat Price</span>
              <span className="font-semibold">₹{trip?.price}</span>
            </div>
          </div>

          <div className="summary-total">
            <span>Total Amount</span>
            <span className="total-price">₹{calculateTotal()}</span>
          </div>

          <button
            className="btn btn-primary checkout-btn"
            disabled={selectedSeats.length === 0}
            onClick={() => navigate(`/checkout?tripId=${tripId}`)}
          >
            Proceed to Checkout <ChevronRight size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};
export default SeatSelection;

